#!/usr/bin/env bash
set -euo pipefail

repo_root="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
env_file="${repo_root}/.env"

if [[ -e "${env_file}" ]]; then
  printf 'ClusterWeave kept the existing %s unchanged.\n' "${env_file}"
  exit 0
fi

random_hex() {
  local bytes="$1"
  if command -v openssl >/dev/null 2>&1; then
    openssl rand -hex "${bytes}"
    return
  fi
  od -An -N "${bytes}" -tx1 /dev/urandom | tr -d ' \n'
}

umask 077
job_secret="$(random_hex 32)"
admin_token="$(random_hex 24)"

{
  printf '%s\n' \
    '# Generated by bin/init_local_instance.sh; keep this file private.' \
    'CLUSTERWEAVE_BIND_ADDRESS=127.0.0.1' \
    'HOST_PORT=8080' \
    'CLUSTERWEAVE_DOCKER_PLATFORM=linux/amd64' \
    'CLUSTERWEAVE_PUBLIC_BASE_URL=http://127.0.0.1:8080/' \
    'CLUSTERWEAVE_PUBLIC_MODE=1' \
    'CLUSTERWEAVE_SUBMISSIONS_OPEN=1' \
    'CLUSTERWEAVE_MAX_CPUS_PER_JOB=4' \
    'CLUSTERWEAVE_WORKER_CPU_LIMIT=4' \
    'CLUSTERWEAVE_WORKER_MEM_LIMIT=16g' \
    'PIPELINE_CPUS=4'
  printf 'CLUSTERWEAVE_JOB_TOKEN_SECRET=%s\n' "${job_secret}"
  printf 'CLUSTERWEAVE_ADMIN_TOKEN=%s\n' "${admin_token}"
} >"${env_file}"
chmod 0600 "${env_file}"

printf 'Created private local configuration: %s\n' "${env_file}"
printf 'After startup, open http://127.0.0.1:8080\n'
